#!/usr/bin/env node
/**
 * Take baseline screenshots from the static mockup HTML (04_result.html)
 * for P04 VRT · 4 states: idle, saving, success, error
 *
 * The mockup only shows the DRAFT/idle state.
 * Other states are generated by injecting CSS/DOM changes.
 */
import { createRequire } from 'module';
const require = createRequire(import.meta.url);
const { chromium } = require('/Users/allen/workspace/longfeng/.claude/worktrees/sc01-t05-result/frontend/node_modules/.pnpm/playwright-core@1.59.1/node_modules/playwright-core');
import { fileURLToPath } from 'url';
import path from 'path';
import fs from 'fs';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, '..');
const MOCKUP = path.join(ROOT, 'design/mockups/wrongbook/04_result.html');
const OUT_DIR = path.join(ROOT, 'design/system/screenshots/baseline');

fs.mkdirSync(OUT_DIR, { recursive: true });

const browser = await chromium.launch({ headless: true });
const context = await browser.newContext({
  viewport: { width: 390, height: 844 },
  deviceScaleFactor: 2,
});

const page = await context.newPage();
await page.goto(`file://${MOCKUP}`);
await page.waitForLoadState('networkidle');

// ─── State 1: idle (DRAFT) ───────────────────────────────────
// The mockup shows the complete result page in idle state.
// We screenshot just the phone screen area (the .screen element inside .phone)
const phone = page.locator('.phone');
await phone.screenshot({ path: path.join(OUT_DIR, 'p04-idle.png') });
console.log('✓ p04-idle.png');

// ─── State 2: saving ─────────────────────────────────────────
// Modify the save button to show loading state
await page.evaluate(() => {
  const btn = document.querySelector('.btn.primary');
  if (btn) {
    btn.innerHTML = `<span style="display:inline-block;width:14px;height:14px;border:2px solid rgba(255,255,255,0.4);border-top-color:#fff;border-radius:50%;margin-right:8px;animation:spin 0.8s linear infinite;vertical-align:middle;"></span> 保存中…`;
    btn.setAttribute('disabled', 'true');
    btn.style.opacity = '0.7';
  }
  // Add spin keyframes
  const style = document.createElement('style');
  style.textContent = '@keyframes spin { to { transform: rotate(360deg); } }';
  document.head.appendChild(style);
});
await phone.screenshot({ path: path.join(OUT_DIR, 'p04-saving.png') });
console.log('✓ p04-saving.png');

// ─── State 3: success ────────────────────────────────────────
// Show a "saved" state - green checkmark overlay or redirect indicator
await page.evaluate(() => {
  const btn = document.querySelector('.btn.primary');
  if (btn) {
    btn.innerHTML = `<svg width="18" height="18" viewBox="0 0 24 24" fill="none"><path d="M5 12.5 10 17l9-10" stroke="#fff" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"/></svg> 已保存`;
    btn.removeAttribute('disabled');
    btn.style.opacity = '1';
    btn.style.background = 'linear-gradient(180deg, #5BD68A, #34C759)';
  }
});
await phone.screenshot({ path: path.join(OUT_DIR, 'p04-success.png') });
console.log('✓ p04-success.png');

// ─── State 4: error ──────────────────────────────────────────
// Restore button + show error toast
await page.evaluate(() => {
  const btn = document.querySelector('.btn.primary');
  if (btn) {
    btn.innerHTML = `<svg viewBox="0 0 24 24" fill="none"><path d="M5 12.5 10 17l9-10" stroke="#fff" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"/></svg>保存并开启复习`;
    btn.style.background = 'linear-gradient(180deg, #5FA8FF, #007AFF)';
  }
  // Add error toast
  const toast = document.createElement('div');
  toast.style.cssText = 'position:fixed;bottom:96px;left:50%;transform:translateX(-50%);background:rgba(0,0,0,0.85);color:#fff;padding:10px 16px;border-radius:8px;font-size:14px;z-index:1100;font-family:-apple-system,BlinkMacSystemFont,sans-serif;';
  toast.textContent = '保存中…稍后自动重试';
  document.body.appendChild(toast);
});
await phone.screenshot({ path: path.join(OUT_DIR, 'p04-error.png') });
console.log('✓ p04-error.png');

await browser.close();
console.log(`\nAll 4 baselines saved to ${OUT_DIR}`);
